def find_generators(n):
 generators = []
 for a in range(1, n):
 # Check if a generates the entire group
 elements = set()
 for k in range(n):
 elements.add((a * k) % n)
 if len(elements) == n:
 generators.append(a)
 return generators

# Example: Find generators of Z7 and Z8
print("Generators of Z7:", find_generators(7)) # [1,2,3,4,5,6]
print("Generators of Z8:", find_generators(8)) # [1,3,5,7]

def is_group(elements, operation, identity):
 """Check if (elements, operation) satisfies group axioms"""
 # 1. Closure
 for a in elements:
 for b in elements:
 if operation(a, b) not in elements:
 return False, "Failed closure"

 # 2. Associativity (simplified check)
 for a in elements:
 for b in elements:
 for c in elements:
 if operation(operation(a, b), c) != operation(a, operation(b, c)):
 return False, "Failed associativity"

 # 3. Identity
 for a in elements:
 if operation(identity, a) != a or operation(a, identity) != a:
 return False, "Failed identity"

 # 4. Inverse
 for a in elements:
 found_inverse = False
 for b in elements:
 if operation(a, b) == identity:
 found_inverse = True
 break
 if not found_inverse:
 return False, "Failed inverse"

 return True, "Valid group"

